import pyotp
import qrcode
import time

class TOTPAuthenticator:
    def __init__(self):
        self.users = {}

    def generate_secret(self, username):
        secret = pyotp.random_base32()
        self.users[username] = secret
        return secret

    def create_qr_code(self, username):
        secret = self.users[username]
        uri = pyotp.totp.TOTP(secret).provisioning_uri(name=username, issuer_name="YourApp")
        img = qrcode.make(uri)
        img.save(f"{username}_qrcode.png")

    def validate_totp(self, username, user_input):
        if username not in self.users:
            return False
        secret = self.users[username]
        totp = pyotp.TOTP(secret)
        return totp.verify(user_input, valid_window=1)

